import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Dashboard({ API_URL, user }) {
  const [services, setServices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [location, setLocation] = useState(null);

  useEffect(() => {
    if (user) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          const loc = {
            lat: pos.coords.latitude,
            lng: pos.coords.longitude
          };
          setLocation(loc);
          fetchNearbyServices(loc);
        },
        (err) => {
          console.error('Location error:', err);
          setLoading(false);
        }
      );
    }
  }, [user]);

  const fetchNearbyServices = async (loc) => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(
        `${API_URL}/services/nearby?lat=${loc.lat}&lng=${loc.lng}&radius=10`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setServices(response.data);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching services:', err);
      setLoading(false);
    }
  };

  const requestService = async (serviceId) => {
    try {
      const token = localStorage.getItem('token');
      await axios.post(
        `${API_URL}/transactions/request`,
        { serviceId },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      alert('Service requested! Check your profile for updates.');
    } catch (err) {
      alert(err.response?.data?.error || 'Request failed');
    }
  };

  if (!user) return <div className="container">Please login</div>;

  return (
    <div>
      <h2>Nearby Services</h2>

      {loading ? (
        <p>Finding services near you...</p>
      ) : (
        <>
          <p style={{ color: '#666', marginBottom: '20px' }}>
            Found {services.length} service providers within 10km
          </p>

          {services.map((service) => (
            <div key={service._id} className="card service-card">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                <div>
                  <h3>{service.title}</h3>
                  <p style={{ color: '#666' }}>{service.description}</p>
                  <p>
                    <strong>Provider:</strong> {service.providerId?.name} 
                    {' '}<span style={{ color: '#FFD700' }}>Ōśģ {service.providerId?.rating}</span>
                  </p>
                  <p className="distance">­¤ōŹ {service.distance} km away</p>
                </div>

                <div style={{ textAlign: 'right' }}>
                  <div className="credit-badge" style={{ marginBottom: '10px' }}>
                    {service.credits} Credits
                  </div>
                  <button 
                    className="btn btn-secondary"
                    onClick={() => requestService(service._id)}
                  >
                    Request
                  </button>
                </div>
              </div>
            </div>
          ))}

          {services.length === 0 && (
            <div className="card" style={{ textAlign: 'center', padding: '40px' }}>
              <p>No services found nearby.</p>
              <p>Be the first to offer a service! Go to Profile to add yours.</p>
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default Dashboard;
